import React, {useContext, useMemo} from "react";
import {type ChartOptions} from "chart.js";
import {Chart} from "primereact/chart";
import ChartContainer from "../WidgetContainer";
import {generateBarData} from "../helpers/data";
import {WidgetsContext} from "../context";
import {type IBarChartProps} from "@lmb-it/kitsconcerto-types";
import {Skeleton} from "primereact/skeleton";

const BarChart = () => {
  const {
    isLoading,
    id = Math.random().toString(16).slice(2),
    data: dataProp,
    aspectRatio,
    colors,
    isDarkMode = false,
  } = useContext(WidgetsContext);

  const { data } = dataProp as IBarChartProps;

  const barOptions = useMemo(() => {
    return {
      color: colors.labels,
      scales: {
        x: {
          grid: {
            color: colors.gridLines,
            tickWidth: 5,
          },
          ticks: {
            color: colors.gridLines,
            textStrokeWidth: 25,
            autoSkip: true,
            maxTicksLimit: 15,
          },
        },
        y: {
          grid: {
            color: colors.gridLines,
            tickWidth: 5,
          },
          ticks: {
            color: colors.gridLines,
            textStrokeWidth: 25,
            autoSkip: true,
            maxTicksLimit: 15,
          },
        },
      },
      elements: {
        line: {
          tension: 0.35,
        },
      },
      responsive: true,
      maintainAspectRatio: false,
      aspectRatio,
      plugins: {
        legend: {
          labels: {
            usePointStyle: true,
          },
        },
      },
    } as ChartOptions<"bar">;
  }, [isDarkMode]);

  return (
    <ChartContainer>
      {!isLoading ? (
        <Chart
          type={"bar"}
          id={id}
          // redraw={true}
          options={barOptions}
          width={"100%"}
          height={"100%"}
          data={generateBarData(data, isDarkMode)}
        />
      ) : (
        <Skeleton height="100%" width={"100%"} />
      )}
    </ChartContainer>
  );
};

export default BarChart;
